import React from 'react';
import { useParams, useNavigate } from 'react-router-dom';

const RateTransaction = () => {
  const { transactionId } = useParams();
  const navigate = useNavigate();

  return (
    <div>
      <h1 className="text-2xl font-semibold text-gray-900 mb-6">Rate Your Purchase</h1>
      <div className="bg-white shadow rounded-lg p-6">
        <p className="text-gray-600">Transaction ID: {transactionId}</p>
        <p className="text-gray-600 mt-2">Rating form coming soon...</p>
        <button
          onClick={() => navigate('/customer/transactions')}
          className="mt-4 px-4 py-2 bg-gray-200 text-gray-800 rounded-md hover:bg-gray-300"
        >
          Back to Transactions
        </button>
      </div>
    </div>
  );
};

export default RateTransaction;
